def procesar_pago(carrito):
    subtotal = 0
    total_articulos = 0
    nombres = []

    for item in carrito:
        subtotal += item['precio'] * item['cantidad']
        total_articulos += item['cantidad']
        nombres.append(item['producto'])

    if total_articulos > 5:
        total = subtotal * 0.85
    else:
        total = subtotal

    return {'total_a_pagar': total, 'nombres_productos': nombres}

