disp = ['Libro A', 'Libro B', 'Libro C']
prestados = []
while True:
    acc = input('¿prestar, devolver o salir?: ').lower()
    if acc == 'salir': break
    elif acc == 'prestar':
        lib = input('Nombre del libro: ')
        if lib in disp:
            disp.remove(lib)
            prestados.append(lib)
            print('Libro prestado.')
        else: print('No disponible.')
    elif acc == 'devolver':
        lib = input('Nombre del libro: ')
        if lib in prestados:
            prestados.remove(lib)
            disp.append(lib)
            print('Libro devuelto.')
        else: print('Ese libro no es nuestro.')

